const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

// 搜索投诉邮件
const complaintsOutput = execSync('node scripts/imap.js search --subject "投诉" --recent 1d').toString();
const complaints = JSON.parse(complaintsOutput);

// 处理每封投诉邮件
complaints.forEach(complaint => {
  // 下载附件
  const downloadDir = path.join('D:\\temp\\complaints', complaint.uid.toString());
  execSync(`mkdir -p ${downloadDir}`);
  execSync(`node scripts/imap.js download ${complaint.uid} --dir ${downloadDir}`);

  // 生成摘要
  const content = execSync(`node scripts/imap.js fetch ${complaint.uid}`).toString();
  const summary = `投诉摘要:\n\n发件人: ${complaint.from}\n主题: ${complaint.subject}\n日期: ${complaint.date}\n\n内容概要: ${content.substring(0, 500)}...`;
  fs.writeFileSync(path.join(downloadDir, 'summary.txt'), summary);
});

console.log(`处理了 ${complaints.length} 封投诉邮件`);
